mapper.select:
SELECT Q.ID,Q.CODE,Q.KEY_POINT_ID,Q.LEV,Q.CONTENT,Q.TYPE,Q.MEMO,Q.LAST_UPDATE_DATE,Q.LAST_UPDATED_BY,
	   Q.CREATION_DATE,Q.CREATED_BY,Q.ENABLED_FLAG,Q.PARSE,Q.RANGE_TYPE
FROM 
	EXAM_QUESTION Q

	,EXAM_KEY_POINT KP

WHERE
	Q.ENABLED_FLAG=1

	AND Q.ID=#{id}


	AND upper(Q.CODE) like upper('%${code}%')


	AND Q.KEY_POINT_ID=#{keyPointId}


	AND upper(Q.LEV) like upper('%${lev}%')


	AND Q.CONTENT=#{content}


	AND upper(Q.TYPE) like upper('%${type}%')


	AND upper(Q.MEMO) like upper('%${memo}%')


	AND Q.LAST_UPDATE_DATE=#{lastUpdateDate}


	AND Q.LAST_UPDATED_BY=#{lastUpdatedBy}


	AND Q.CREATION_DATE=#{creationDate}


	AND Q.CREATED_BY=#{createdBy}


	AND Q.ENABLED_FLAG=#{enabledFlag}


	AND Q.PARSE=#{parse}


	AND upper(Q.RANGE_TYPE) like upper('%${rangeType}%')


	AND Q.KEY_POINT_ID=KP.ID
	AND KP.COURSE_ID=#{courseId}

	ORDER BY Q.ID

SELECT Q.ID,Q.CODE,Q.KEY_POINT_ID,Q.LEV,Q.CONTENT,Q.TYPE,Q.MEMO,Q.LAST_UPDATE_DATE,Q.LAST_UPDATED_BY,
	   Q.CREATION_DATE,Q.CREATED_BY,Q.ENABLED_FLAG,Q.PARSE,Q.RANGE_TYPE
FROM 
	EXAM_QUESTION Q

	,EXAM_KEY_POINT KP

WHERE
	Q.ENABLED_FLAG=1

	AND Q.ID=#{bo.id}


	AND upper(Q.CODE) like upper('%${bo.code}%')


	AND Q.KEY_POINT_ID=#{bo.keyPointId}


	AND upper(Q.LEV) like upper('%${bo.lev}%')


	AND Q.CONTENT=#{bo.content}


	AND upper(Q.TYPE) like upper('%${bo.type}%')


	AND upper(Q.MEMO) like upper('%${bo.memo}%')


	AND Q.LAST_UPDATE_DATE=#{bo.lastUpdateDate}


	AND Q.LAST_UPDATED_BY=#{bo.lastUpdatedBy}


	AND Q.CREATION_DATE=#{bo.creationDate}


	AND Q.CREATED_BY=#{bo.createdBy}


	AND Q.ENABLED_FLAG=#{bo.enabledFlag}


	AND Q.PARSE=#{bo.parse}


	AND upper(Q.RANGE_TYPE) like upper('%${bo.rangeType}%')


	AND Q.KEY_POINT_ID=KP.ID
	AND KP.COURSE_ID=#{bo.courseId}

	ORDER BY ${page.sortFieldName} DESC

SELECT CONCAT(TYPE,LEV) as type,count(1) as typeNum FROM EXAM_QUESTION WHERE ENABLED_FLAG=1 AND RANGE_TYPE=#{rangeType} AND KEY_POINT_ID IN
#{id}
GROUP BY TYPE,LEV
